  `buff_image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Buff鍥剧墖',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3030533 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Buff琛';
