--
-- Table structure for table `character`
--

DROP TABLE IF EXISTS `character`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `character` (
  `id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '角色ID',
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '角色名称',
  `profession` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '职业',
  `element` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '属性',
  `support_needs` json NOT NULL COMMENT '辅助需求属性数组',
  `avatar_image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '头像路径',
  `note` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '注释',
  `base_panel` json NOT NULL,
  `mindscape_notes` json NOT NULL COMMENT '0-6影画注释数组',
  `mindscape_buffs` json NOT NULL COMMENT '0-6影画增益数组',
  `raw_json` json NOT NULL COMMENT '原始完整文档，防丢字段',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='角色增益表';
/*!40101 SET character_set_client = @saved_cs_client */;

