ompMult\": 7.5, \"disorderDmgBonus\": 0, \"turbulenceBaseMult\": 800, \"turbulenceCompMult\": 7.5, \"turbulenceDmgBonus\": 0}','[\"基础异常暴击率为40%，异常暴伤为50%，简的每点异常精通会使该效果的暴击率额外提升0.16%，375点精通吃满。\\n\\n[狂热]状态下，简异常精通高于120点，每超过1点异常精通会使自身的攻击力提升2点；\\n通过这种方式最多使自身的攻击力提升600点；\\n\\n若简为队友，且不为物理属性，请将异常爆伤置为0。\", \"[狂热]状态下，每点异常精通将会使自身造成的伤害提升0.1%，最多提升30%。\", \"任意角色对处于[啮咬]状态下的敌人触发[强击]时，将会无视其15%防御力；\\n（注意：这里的无视防御不会参与紊乱伤害的计算！）\\n\\n当[强击]伤害触发暴击时，其暴击伤害额外提升50%。\\n\\n若简为队友，且不为物理属性，请将异常爆伤置为0，并减去15%减防。\", \"\", \"独立乘区：队伍中任意角色触发[强击]或[紊乱]效果时，全队角色造成的属性异常伤害提升18%，持续15秒。\\n（！！！注意：此处的属性异常伤害提升18%对异常伤害和[紊乱]，均生效！！！）\\n（也就是，异常伤害的独立乘区 和 [紊乱]伤害的独立乘区 均有18%的加成，但二者仍是只对对应伤害生效！）\", \"\", \"[狂热]状态下，简的暴击率提升20%，暴击伤害提升40%（此处均为直伤加成）\\n\\n若简为队友，且不为物理属性，请将异常爆伤置为0。\"]','[{\"selfMods\": {\"atk\": 600, \"pierce\": 0, \"resPen\": 0, \"critDmg\": 0, \"mastery\": 0, \"penRate\": 0, \"special\": 0, \"critRate\": 0, \"dmgBonus\": 0, \"vulnerable\": 0, \"anomalyMult\": 0, \"directDmgMult\": 0, \"reduceDefense\": 0, \"anomalyCritDmg\": 50, \"anomalyCritRate\": 100, \"anomalyDmgBonus\": 0, \"anomalyDuration\": 5, \"disorderBaseMult\": 0, \"disorderCompMult\": 0, \"disorderDmgBonus\": 0, \"externalHpPercent\": 0, \"inCombatHpPercent\": 0, \"staggerVulnerable\": 0, \"externalAtkPercent\": 0, \"inCombatAtkPercent\": 0, \"turbulenceBaseMult\": 0, \"turbulenceCompMult\": 0, \"turbulenceDmgBonus\": 0}, \"teamMods\": {\"atk\": 0, \"pierce\": 0, \"resPen\": 0, \"critDmg\": 0, \"mastery\": 0, \"penRate\": 0, \"special\": 0, \"critRate\": 0, \"dmgBonus\": 0, \"vulnerable\": 0, \"anomalyMult\": 0, \"directDmgMult\": 0, \"reduceDefense\": 0, \"anomalyCritDmg\": 50, \"anomalyCritRate\": 100, \"anomalyDmgBonus\": 0, \"anomalyDuration\": 5, \"disorderBaseMult\": 0, \"disorderCompMult\": 0, \"disorderDmgBonus\": 0, \"externalHpPercent\": 0, \"inCombatHpPercent\": 0, \"staggerVulnerable\": 0, \"externalAtkPercent\": 0, \"inCombatAtkPercent\": 0, \"turbulenceBaseMult\": 0, \"turbulenceCompMult\": 0, \"turbulenceDmgBonus\": 0}}, {\"selfMods\": {\"at