/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `drive_disc` (
  `id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '驱动盘ID',
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '驱动盘名称',
  `avatar_image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '头像路径',
  `two_piece_note` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '2件套注释',
  `four_piece_note` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '4件套注释',
  `two_piece_mods` json NOT NULL COMMENT '2件套增益',
  `four_piece_buffs` json NOT NULL COMMENT '4件套自身/队友增益',
  `raw_json` json NOT NULL COMMENT '原始完整文档，防丢字段',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='驱动盘增益表';
/*!40101 SET character_set_client = @saved_cs_client */;

