INSERT INTO `drive_disc` VALUES ('chaos-jazz','混沌爵士','/calculator_image/SuitChaosJazz.webp','','火属性伤害和电属性伤害提升15%；位于后场时，[强化特殊技]和[支援攻击]造成的伤害提升20%，换入前场后，该增益效果仍然保留，持续5秒，保留效果7.5秒内最多触发一次。\n\n[强化特殊技]和[支援攻击]造成的伤害提升20%计算在内，其他动作请自行减掉20%增伤。','{\"atk\": 0, \"pierce\": 0, \"resPen\": 0, \"critDmg\": 0, \"mastery\": 30, \"penRate\": 0, \"special\": 0, \"critRate\": 0, \"dmgBonus\": 0, \"vulnerable\": 0, \"reduceDefense\": 0, \"externalHpPercent\": 0, \"inCombatHpPercent\": 0, \"staggerVulnerable\": 0, \"externalAtkPercent\": 0, \"inCombatAtkPercent\": 0}','{\"selfMods\": {\"atk\": 0, \"pierce\": 0, \"resPen\": 0, \"critDmg\": 0, \"mastery\": 0, \"penRate\": 0, \"special\": 0, \"critRate\": 0, \"dmgBonus\": 35, \"vulnerable\": 0, \"reduceDefense\": 0, \"externalHpPercent\": 0, \"inCombatHpPercent\": 0, \"staggerVulnerable\": 0, \"externalAtkPercent\": 0, \"inCombatAtkPercent\": 0}, \"teamMods\": {\"atk\": 0, \"pierce\": 0, \"resPen\": 0, \"critDmg\": 0, \"mastery\": 0, \"penRate\": 0, \"special\": 0, \"critRate\": 0, \"dmgBonus\": 0, \"vulnerable\": 0, \"reduceDefense\": 0, \"externalHpPercent\": 0, \"inCombatHpPercent\": 0, \"staggerVulnerable\": 0, \"externalAtkPercent\": 0, \"inCombatAtkPercent\": 0}}','{\"id\": \"chaos-jazz\", \"name\": \"混沌爵士\", \"avatar_image\": \"/calculator_image/SuitChaosJazz.webp\", \"twoPieceMods\": {\"atk\": 0, \"pierce\": 0, \"resPen\": 0, \"critDmg\": 0, \"mastery\": 30, \"penRate\": 0, \"special\": 0, \"critRate\": 0, \"dmgBonus\": 0, \"vulnerable\": 0, \"reduceDefense\": 0, \"externalHpPercent\": 0, \"inCombatHpPercent\": 0, \"staggerVulnerable\": 0, \"externalAtkPercent\": 0, \"inCombatAtkPercent\": 0}, \"twoPieceNote\": \"\", \"fourPieceNote\": \"火属性伤害和电属性伤害提升15%；位于后场时，[强化特殊技]和[支援攻击]造成的伤害提升20%，换入前场后，该增益效果仍然保留，持续5秒，保留效果7.5秒内最多触发一次。\\n\\n[强化特殊技]和[支援攻击]造成的伤害提升20%计算在内，其他动作请自行减掉20%增伤。\", \"fourPieceBuffs\": {\"selfMods\": {\"atk\": 0, \"pierce\": 0, \"resPen\": 0, \"critDmg\": 0, \"mastery\": 0, \"penRate\": 0, \"special\": 0, \"critRate\": 0, \"dmgBo